                : Constants.ANY_PATTERN + target + Constants.ANY_PATTERN;
    }

    private Collection<Service> doPage(Collection<Service> services, int pageNo, int pageSize) {
        if (pageNo == 0 && services.size() < pageSize) {
            return services;
